/*
Expect msg.payload = {x,y} from the UI joystick.
Adds msg.source, msg.session and normalizes payload.
*/

function num(v, d=0){
  const n = Number(v);
  return Number.isFinite(n) ? n : d;
}

if (!msg.payload || typeof msg.payload !== 'object') return null;

const x = num(msg.payload.x, 0);
const y = num(msg.payload.y, 0);

// Best-effort session extraction (Dashboard 2 varies a bit)
const session = msg.session
  || msg._sessionid
  || (msg._client && (msg._client.socketid || msg._client.id))
  || msg.socketid
  || msg._socketId
  || msg._msgid;

msg.payload = { x, y };
msg.source = 'joystick';
msg.session = session;
msg.topic = 'joystick';

return msg;

/*
Ownership lock:
- One session owns joystick at a time.
- If owner is silent for CLAIM_TIMEOUT_MS, lock releases.
- Only owner messages pass through.
*/

const CLAIM_TIMEOUT_MS = 1000;

const now = Date.now();
const session = msg.session;
if (!session) return null;

let owner = context.get('owner') || null;
let lastSeen = context.get('lastSeen') || 0;

// Release stale owner
if (owner && (now - lastSeen) > CLAIM_TIMEOUT_MS) {
  owner = null;
}

// Claim if free
if (!owner) {
  owner = session;
}

// Only owner passes
if (session !== owner) {
  node.status({fill:'yellow', shape:'ring', text:`reject ${session} (owner ${owner})`});
  return null;
}

lastSeen = now;
context.set('owner', owner);
context.set('lastSeen', lastSeen);

msg.owner = owner;
node.status({fill:'green', shape:'dot', text:`owner ${owner} x:${msg.payload.x} y:${msg.payload.y}`});
return msg;

