/*
Stores last message from each source and selects highest priority.
Priority order: safety > override > autopilot > joystick

Input must have:
- msg.source in {'safety','override','autopilot','joystick'}
- msg.payload {x,y}

Output: selected msg with msg.selectedSource
*/

const PRIO = ['safety','override','autopilot','joystick'];

const src = msg.source || msg.topic;
if (!src) return null;

// Store last msg per source
flow.set(`src:${src}:msg`, {
  payload: msg.payload,
  source: src,
  owner: msg.owner,
  session: msg.session,
  ts: Date.now()
});

// Helper: source active flag (set by presence of recent msg)
// You can tighten these timeouts later per source.
const ACTIVE_MS = {
  safety: 500,
  override: 800,
  autopilot: 800,
  joystick: 400
};

let selected = null;
for (const s of PRIO) {
  const m = flow.get(`src:${s}:msg`);
  if (!m) continue;
  const age = Date.now() - (m.ts || 0);
  if (age <= (ACTIVE_MS[s] || 500)) {
    selected = m;
    break;
  }
}

// If nothing active, output nothing (watchdog will force zero)
if (!selected) {
  node.status({fill:'grey', shape:'ring', text:'no active source'});
  return null;
}

node.status({fill:'blue', shape:'dot', text:`active ${selected.source} x:${selected.payload.x} y:${selected.payload.y}`});
return {
  payload: selected.payload,
  selectedSource: selected.source,
  owner: selected.owner,
  session: selected.session,
  topic: 'selected'
};

/*
Updates watchdog lastSeen and lastOut whenever we have a selected output.
*/

const now = Date.now();
flow.set('wd:lastSeen', now);
flow.set('wd:lastOut', msg.payload);
flow.set('wd:lastSource', msg.selectedSource || msg.source || 'unknown');
return msg;

/*
Forces 0,0 if no selected output seen within TIMEOUT_MS.
Also sends 0,0 twice for reliability.
*/

const TIMEOUT_MS = 300;

const now = Date.now();
const lastSeen = flow.get('wd:lastSeen') || 0;
const lastOut = flow.get('wd:lastOut') || {x:0,y:0};
const lastSource = flow.get('wd:lastSource') || 'none';

if ((now - lastSeen) > TIMEOUT_MS) {
  node.status({fill:'red', shape:'dot', text:`TIMEOUT (${lastSource}) -> 0,0`});
  // Two zero messages
  const z1 = { payload:{x:0,y:0}, selectedSource:'watchdog', reason:'timeout' };
  const z2 = { payload:{x:0,y:0}, selectedSource:'watchdog', reason:'timeout2' };
  // Emit first now; second as a separate output via context flag
  context.set('wd:pendingZero2', true);
  return [z1];
}

// optional: you can keepalive lastOut here if wanted, but default is silent
node.status({fill:'green', shape:'ring', text:`ok (${lastSource})`});
return null;

const pending = context.get('wd:pendingZero2') || false;
if (!pending) return null;
context.set('wd:pendingZero2', false);
msg.payload = {x:0,y:0};
msg.selectedSource = 'watchdog';
msg.reason = 'timeout2';
return msg;

