// INPUT:
// msg.payload = joystick verdi (-100 ... 100)

// OUTPUT:
// msg.payload = registerverdi (0x00CA)
// + debug info i msg.jog

let joy = Number(msg.payload);
if (isNaN(joy)) return null;

// Deadband rundt null (hindrer "dirring")
const deadband = 5;

// Register limits
const MAX_SPEED = 511;

let direction = 0;   // 0 = CW, 1 = CCW
let speed = 0;
let stopMode = 0;    // 0 = decelerate stop
let startStop = 0;   // 0 = stop, 1 = run

if (Math.abs(joy) <= deadband) {
    // STOP
    startStop = 0;
    speed = 0;
} else {
    // RUN
    startStop = 1;
    direction = (joy < 0) ? 1 : 0;

    // map (deadband..100) -> (0..511)
    let mag = Math.abs(joy);
    let scaled = (mag - deadband) / (100 - deadband);

    if (scaled < 0) scaled = 0;
    if (scaled > 1) scaled = 1;

    speed = Math.round(scaled * MAX_SPEED);
}

// bygg register
let regValue =
    (direction << 15) |
    (speed << 6) |
    (stopMode << 5) |
    (startStop);

// output
msg.payload = regValue;

// debug/info (veldig nyttig i ditt oppsett)
msg.jog = {
    joystick: joy,
    direction: direction === 0 ? "CW" : "CCW",
    speed,
    start: startStop,
    stopMode,
    hex: "0x" + regValue.toString(16).toUpperCase().padStart(4, "0")
};

return msg;

