 *
 * Output 1: next Modbus request, loop back to modbus-flex-getter
 * Output 2: finished result for dashboard/debug
 */

function u16(v) { return v & 0xFFFF; }
function i16(v) {
    v = v & 0xFFFF;
    return v & 0x8000 ? v - 0x10000 : v;
}
function u32(words) {
    return ((words[0] & 0xFFFF) << 16) + (words[1] & 0xFFFF);
}
function i32(words) {
    let v = u32(words);
    return v > 0x7FFFFFFF ? v - 0x100000000 : v;
}
function decodeStatus(v) {
    const runningBits = (v >> 9) & 0x03;
    return {
        raw: v,
        alarm: !!(v & (1 << 21)),
        position_deviation_warning: !!(v & (1 << 10)),
        in_position: !!(v & (1 << 12)),
        software_negative_limit: !!(v & (1 << 13)),
        software_positive_limit: !!(v & (1 << 14)),
        origin_complete: !!(v & (1 << 15)),
        enable_level_flag: !!(v & (1 << 16)),
        running_state_bits: runningBits,
        running_state:
            runningBits === 0 ? 'Idle' :
            runningBits === 1 ? 'About to start' :
            runningBits === 2 ? 'About to stop' :
            'Running',
        inputs: {
            x0: !!(v & (1 << 0)),
            x1: !!(v & (1 << 1)),
            x2: !!(v & (1 << 2)),
            x3: !!(v & (1 << 3)),
            x4: !!(v & (1 << 4)),
            x5: !!(v & (1 << 5)),
            x6: !!(v & (1 << 6)),
            x7: !!(v & (1 << 7))
        }
    };
}
function getDataArray(msg) {
    if (Array.isArray(msg.payload)) return msg.payload;
    if (Array.isArray(msg.payload?.data)) return msg.payload.data;
    if (Array.isArray(msg.responseBuffer?.data)) return msg.responseBuffer.data;
    return null;
}

