    for (const address of addresses) {
        queue.push({
            axis: ax.axis,
            unitid: ax.unitid,
            address
        });
    }
}

flow.set('motor_peak_reset_meta', {
    started: new Date().toISOString(),
    action: 'reset_peaks_both',
    count: queue.length
});

let req = queue.shift();

if (!req) {
    flow.set('motor_poll_paused', false);
    node.status({ fill: 'grey', shape: 'ring', text: 'no reset requests' });
    return null;
}

flow.set('motor_peak_reset_queue', queue);

msg.resetReq = req;

msg.payload = {
    value: [0],
    fc: 6,
    unitid: req.unitid,
    address: req.address,
    quantity: 1
};

node.status({
    fill: 'orange',
    shape: 'dot',
    text: `reset ${req.axis} 0x${req.address.toString(16)}`
});

return msg;

/*
 * Peak reset collector.
 * Output 1: next write request
 * Output 2: done message
 */

let queue = flow.get('motor_peak_reset_queue') || [];

if (queue.length > 0) {
    let req = queue.shift();
    flow.set('motor_peak_reset_queue', queue);

    let nextMsg = {
        resetReq: req,
        payload: {
            value: [0],
            fc: 6,
            unitid: req.unitid,
            address: req.address,
            quantity: 1
        }
    };

    node.status({ fill: 'orange', shape: 'dot', text: `reset ${req.axis} 0x${req.address.toString(16)}` });
    return [nextMsg, null];
}

flow.set('motor_poll_paused', false);

let meta = flow.get('motor_peak_reset_meta') || {};
meta.finished = new Date().toISOString();

node.status({ fill: 'green', shape: 'dot', text: 'peak reset done, polling resumed' });

return [null, {
    topic: 'motor_peak_reset',
    payload: {
        ok: true,
        meta,
        note: 'Peak registers 0x0044-0x0048 reset to 0 for both axes. Normal polling resumed.'
    }
}];
